classDiagram(name = "CinemaBoxOffice") {
    val film = classOf(name = "Film") {
        attribute(name = "title", type = "String")
        attribute(name = "durationMinutes", type = "Int")
    }
    val auditorium = classOf(name = "Auditorium") {
        attribute(name = "name", type = "String")
    }
    val seat = classOf(name = "Seat") {
        attribute(name = "row", type = "String")
        attribute(name = "number", type = "Int")
    }
    val screening = classOf(name = "Screening") {
        attribute(name = "startTime", type = "String")
    }
    val ticket = classOf(name = "Ticket") {
        attribute(name = "price", type = "Double")
    }

    // Screening shows Film (1 Film can have 0..* Screenings; 1 Screening shows 1 Film)
    association(source = film, target = screening) {
        source { multiplicity(spec = "1"); role = "screenings" }
        target { multiplicity(spec = "0..*"); role = "film" }
    }

    // Screening takes place in Auditorium (1 Auditorium can have 0..* Screenings; 1 Screening is in 1 Auditorium)
    association(source = auditorium, target = screening) {
        source { multiplicity(spec = "1"); role = "hostedScreenings" }
        target { multiplicity(spec = "0..*"); role = "auditorium" }
    }

    // Auditorium consists of Seats (Composite aggregation: 1 Auditorium has 1..* Seats; 1 Seat belongs to 1 Auditorium)
    association(source = auditorium, target = seat) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1"); role = "seats" }
        target { multiplicity(spec = "1..*"); role = "auditorium" }
    }

    // Ticket belongs to Screening (1 Screening can have 0..* Tickets; 1 Ticket belongs to 1 Screening)
    association(source = screening, target = ticket) {
        source { multiplicity(spec = "1"); role = "tickets" }
        target { multiplicity(spec = "0..*"); role = "screening" }
    }

    // Ticket reserves Seat (1 Ticket reserves 1 Seat; 1 Seat can be reserved by 0..* Tickets (over different screenings))
    association(source = ticket, target = seat) {
        source { multiplicity(spec = "1"); role = "seat" }
        target { multiplicity(spec = "0..*"); role = "reservedByTickets" }
    }
}

