classDiagram(name = "BankModel") {
    val customer = classOf(name = "Customer") {}

    val account = classOf(name = "Account") {
        isAbstract = true
        attribute(name = "iban", type = "String")
        attribute(name = "balance", type = "Double")
    }

    val interestContract = classOf(name = "InterestContract") {
        isAbstract = true
        operation(name = "calculateInterest") { returns(typeName = "Double") }
    }

    val transactionType = classOf(name = "TransactionType") {
        // Typically an enum, represented as a class here as per DSL limitations
        attribute(name = "name", type = "String") // e.g., "deposit", "withdrawal", "transfer"
    }

    val checkingAccount = classOf(name = "CheckingAccount") {
        extends(general = account)
        attribute(name = "overdraftLimit", type = "Double")
    }

    val savingsAccount = classOf(name = "SavingsAccount") {
        extends(general = account)
        attribute(name = "interestRate", type = "Double")
        // "implements an interest contract" is modeled by the presence of InterestContract,
        // but explicit 'realization' line is not available in the given DSL shape.
    }

    val transaction = classOf(name = "Transaction") {
        attribute(name = "amount", type = "Double")
        attribute(name = "timestamp", type = "Instant")
    }

    association(source = customer, target = account) {
        source { multiplicity(spec = "1"); role = "customer" }
        target { multiplicity(spec = "0..*"); role = "accounts" }
    }

    association(source = account, target = transaction) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1"); role = "transactions" }
        target { multiplicity(spec = "0..*"); role = "account" }
    }

    association(source = transaction, target = transactionType) {
        source { multiplicity(spec = "1"); role = "type" }
        target { multiplicity(spec = "0..*"); role = "transactions" }
    }
}

@startuml
abstract class Account {
  - IBAN: String
  - balance: Money
}

class Customer {
  ' Add customer specific attributes here, e.g.,
  ' - customerId: String
  ' - name: String
  ' - address: String
}

class CheckingAccount {
  - overdraftLimit: Money
}

class SavingsAccount {
  - interestRate: BigDecimal
}

class Transaction {
  - amount: Money
  - timestamp: DateTime
  - type: TransactionType
}

interface InterestContract {
  + calculateInterest(account: Account): Money
}

' Inheritance
CheckingAccount <|-- Account
SavingsAccount <|-- Account

' Implementation
SavingsAccount ..|> InterestContract

' Composition: An account movement only exists in the context of its account.
Account "1" *-- "0..*" Transaction : records

' Composition: An account belongs to exactly one customer, and a customer can have multiple accounts.
' Implies strong ownership, if customer is deleted, accounts are typically closed/deleted.
Customer "1" *-- "0..*" Account : maintains
@enduml

