classDiagram(name = "PersonnelManagementSystem") {
    // Interfaces
    val approvalContract = interfaceOf(name = "ApprovalContract") {
        operation(name = "approve")
        operation(name = "reject")
    }

    // Classes
    val employee = classOf(name = "Employee") {
        attribute(name = "name", type = "String")
        attribute(name = "employeeId", type = "String")
    }

    val department = classOf(name = "Department") {
        attribute(name = "name", type = "String")
        attribute(name = "departmentId", type = "String")
    }

    val position = classOf(name = "Position") {
        attribute(name = "title", type = "String")
        attribute(name = "description", type = "String")
    }

    val leaveRequest = classOf(name = "LeaveRequest") {
        attribute(name = "startDate", type = "Date")
        attribute(name = "endDate", type = "Date")
        attribute(name = "status", type = "String") // e.g., "Submitted", "Approved", "Rejected"
    }

    val payrollRecord = classOf(name = "PayrollRecord") {
        attribute(name = "month", type = "Date")
        attribute(name = "amount", type = "Double")
    }

    // Subclasses
    val manager = classOf(name = "Manager") {
        extends(general = employee)
        attribute(name = "budget", type = "Double")
    }

    // Relationships

    // LeaveRequest implements ApprovalContract
    realization(implementing = leaveRequest, iface = approvalContract)

    // Employee - Department: An employee is assigned to exactly one department; a department has at least one employee.
    association(source = employee, target = department) {
        source { multiplicity(spec = "1"); role = "assignedTo" }
        target { multiplicity(spec = "1..*"); role = "has" }
    }

    // Employee - Position: An employee is assigned to exactly one position.
    association(source = employee, target = position) {
        source { multiplicity(spec = "1"); role = "holds" }
        target { multiplicity(spec = "1..*"); role = "filledBy" }
    }

    // Department - Manager: Each department is led by exactly one manager.
    association(source = department, target = manager) {
        source { multiplicity(spec = "1"); role = "ledBy" }
        target { multiplicity(spec = "0..*"); role = "leads" }
    }

    // Employee - LeaveRequest: Employees submit leave requests.
    association(source = employee, target = leaveRequest) {
        source { multiplicity(spec = "0..*"); role = "submits" }
        target { multiplicity(spec = "1"); role = "submittedBy" }
    }

    // Employee - PayrollRecord: Monthly payroll records only exist in the context of the respective employee. (Composite Aggregation)
    association(source = employee, target = payrollRecord) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "0..*"); role = "records" }
        target { multiplicity(spec = "1"); role = "belongsTo" }
    }
}

