sequenceDiagram(name = "CollisionAvoidanceSystem") {
    val cameraSensor = lifeline(name = "Camera Sensor") { isActor = true }
    val radarSensor = lifeline(name = "Radar Sensor") { isActor = true }
    val fusionUnit = lifeline(name = "Fusion Unit")
    val emergencyBrakingAssistant = lifeline(name = "Emergency Braking Assistant")
    val driver = lifeline(name = "Driver") { isActor = true }
    val controlUnit = lifeline(name = "Control Unit")
    val diagnosticLog = lifeline(name = "Diagnostic Log")

    message(from = cameraSensor, to = fusionUnit, label = "Measurement data")
    message(from = radarSensor, to = fusionUnit, label = "Measurement data")
    message(from = fusionUnit, to = emergencyBrakingAssistant, label = "Collision risk (time-to-collision)")

    alt {
        operand("Time-to-collision below critical threshold") {
            message(from = emergencyBrakingAssistant, to = driver, label = "Warn acoustically")
            message(from = emergencyBrakingAssistant, to = controlUnit, label = "Initiate autonomous braking")
            loop("Adjust brake pressure until vehicle stationary") {
                message(from = emergencyBrakingAssistant, to = controlUnit, label = "Adjust brake pressure")
                reply(from = controlUnit, to = emergencyBrakingAssistant, label = "Brake pressure applied")
            }
            message(from = emergencyBrakingAssistant, to = diagnosticLog, label = "Record event")
        }
        operand("Time-to-collision above critical threshold") {
            message(from = emergencyBrakingAssistant, to = driver, label = "Show distance warning")
            message(from = emergencyBrakingAssistant, to = diagnosticLog, label = "Log observed risk")
        }
    }
}

