import dev.kuml.sysml2.dsl.sysml2Model

sysml2Model(name = "RobotArmModel") {
    // Declare all partDefs as vals, including their properties and compositions within their blocks
    val base = partDef(name = "Base")

    // Define joint first so it can be referenced by revoluteJoint and prismaticJoint
    val joint = partDef(name = "Joint") {
        isAbstract = true
    }

    val revoluteJoint = partDef(name = "RevoluteJoint") {
        specializes(joint.id)
    }

    val prismaticJoint = partDef(name = "PrismaticJoint") {
        specializes(joint.id)
    }

    val endEffector = partDef(name = "EndEffector")

    // Define RobotArm, referencing other partDefs
    val robotArm = partDef(name = "RobotArm") {
        part(name = "theBase", typeId = base.id, min = 1, max = 1)
        part(name = "theJoint", typeId = joint.id, min = 1, max = 6) // Between one and six joints
        part(name = "theEndEffector", typeId = endEffector.id, min = 1, max = 1)
    }

    bdd(name = "RobotArm BDD") {
        include(robotArm)
        include(base)
        include(joint)
        include(revoluteJoint)
        include(prismaticJoint)
        include(endEffector)
    }
}

