import dev.kuml.sysml2.dsl.sysml2Model

sysml2Model(name = "ADAS Vehicle Subsystem Model") {
    // 1. Define abstract base block and external interaction targets
    val sensor = partDef(name = "Sensor", isAbstract = true)
    val steeringSystem = partDef(name = "Steering System")
    val brakingSystem = partDef(name = "Braking System")

    // 2. Define concrete sensors and their inheritance from Sensor
    val cameraSensor = partDef(name = "Camera Sensor", general = sensor.id)
    val radarUnit = partDef(name = "Radar Unit", general = sensor.id)
    val lidarScanner = partDef(name = "Lidar Scanner", general = sensor.id)

    // 3. Define Sensor Suite, containing specific sensors
    // Multiplicity (e.g., "at least one lidar scanner") cannot be expressed directly
    // with `part(name=..., typeId=...)` as per the provided shape and error message.
    // The presence of the part implies its existence.
    val sensorSuite = partDef(name = "Sensor Suite") {
        part(name = "camera", typeId = cameraSensor.id) // Represents one or more camera sensors
        part(name = "radar", typeId = radarUnit.id)     // Represents one or more radar units
        part(name = "lidar", typeId = lidarScanner.id)   // Represents at least one lidar scanner
    }

    // 4. Define Fusion and Processing Unit
    val fusionProcessingUnit = partDef(name = "Fusion and Processing Unit")

    // 5. Define Driver Assistance Control Unit
    val driverAssistanceControlUnit = partDef(name = "Driver Assistance Control Unit")

    // 6. Define ADAS Subsystem, composing the major units
    val adasSubsystem = partDef(name = "ADAS Subsystem") {
        part(name = "sensorSuite", typeId = sensorSuite.id)
        part(name = "fusionUnit", typeId = fusionProcessingUnit.id)
        part(name = "driverControl", typeId = driverAssistanceControlUnit.id)
    }

    // BDD block to render all defined partDefs
    bdd(name = "ADAS Subsystem BDD") {
        include(adasSubsystem)
        include(sensorSuite)
        include(fusionProcessingUnit)
        include(driverAssistanceControlUnit)
        include(sensor)
        include(cameraSensor)
        include(radarUnit)
        include(lidarScanner)
        include(steeringSystem)
        include(brakingSystem)
    }
}

