classDiagram(name = "HospitalInformationSystem") {
    // Declare all classes first
    val personalData = classOf(name = "PersonalData") {
        isAbstract = true
    }
    val patient = classOf(name = "Patient") {
        extends(general = personalData)
    }
    val doctor = classOf(name = "Doctor") {
        extends(general = personalData)
    }
    val nursingStaff = classOf(name = "NursingStaff") {
        extends(general = personalData)
    }
    val ward = classOf(name = "Ward")
    val bed = classOf(name = "Bed")
    val inpatientStay = classOf(name = "InpatientStay") {
        attribute(name = "admissionType", type = "String") // emergency, planned, transfer
    }
    val diagnosis = classOf(name = "Diagnosis")
    val prescription = classOf(name = "Prescription") {
        attribute(name = "dosage", type = "String")
    }
    val medication = classOf(name = "Medication")
    val insuranceCompany = classOf(name = "InsuranceCompany")
    val invoice = classOf(name = "Invoice")
    val billingContract = classOf(name = "BillingContract")

    // Associations
    // Patient - InsuranceCompany: Each patient is insured by exactly one insurance company
    association(source = patient, target = insuranceCompany) {
        source { multiplicity(spec = "1"); role = "insuredBy" }
        target { multiplicity(spec = "0..*"); role = "insures" }
    }

    // Ward - Bed: Wards consist of beds
    association(source = ward, target = bed) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1..*"); role = "contains" }
        target { multiplicity(spec = "1"); role = "partOf" }
    }

    // Ward - NursingStaff: Wards are staffed by at least one nurse
    association(source = ward, target = nursingStaff) {
        source { multiplicity(spec = "1..*"); role = "staffedBy" }
        target { multiplicity(spec = "0..*"); role = "assignedTo" }
    }

    // InpatientStay - Patient: each inpatient stay belongs to exactly one patient
    association(source = inpatientStay, target = patient) {
        source { multiplicity(spec = "1"); role = "belongsTo" }
        target { multiplicity(spec = "0..*"); role = "hasStays" }
    }

    // InpatientStay - Bed: occupies at most one bed
    association(source = inpatientStay, target = bed) {
        source { multiplicity(spec = "0..1"); role = "occupies" }
        target { multiplicity(spec = "0..1"); role = "occupiedBy" }
    }

    // InpatientStay - Doctor (Attending Physician): has exactly one attending physician
    association(source = inpatientStay, target = doctor) {
        source { multiplicity(spec = "1"); role = "attendedBy" }
        target { multiplicity(spec = "0..*"); role = "attends" }
    }

    // InpatientStay - Diagnosis: Diagnoses belong inseparably to the stay
    association(source = inpatientStay, target = diagnosis) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "0..*"); role = "hasDiagnoses" }
        target { multiplicity(spec = "1"); role = "partOf" }
    }

    // Diagnosis - Doctor: each diagnosis is the responsibility of exactly one doctor
    association(source = diagnosis, target = doctor) {
        source { multiplicity(spec = "1"); role = "responsibleBy" }
        target { multiplicity(spec = "0..*"); role = "responsibleFor" }
    }

    // Diagnosis - Prescription: prescriptions can be issued for a diagnosis
    association(source = diagnosis, target = prescription) {
        source { multiplicity(spec = "0..*"); role = "hasPrescriptions" }
        target { multiplicity(spec = "1"); role = "issuedFor" }
    }

    // Prescription - Medication: specifying exactly one medication with dosage
    association(source = prescription, target = medication) {
        source { multiplicity(spec = "1"); role = "specifies" }
        target { multiplicity(spec = "0..*"); role = "specifiedBy" }
    }

    // InpatientStay - Invoice: each stay generates exactly one invoice
    association(source = inpatientStay, target = invoice) {
        source { multiplicity(spec = "1"); role = "generates" }
        target { multiplicity(spec = "1"); role = "generatedBy" }
    }

    // Invoice - BillingContract: invoice follows a uniform billing contract
    association(source = invoice, target = billingContract) {
        source { multiplicity(spec = "1"); role = "follows" }
        target { multiplicity(spec = "0..*"); role = "followedBy" }
    }

    // Invoice - InsuranceCompany: submitted to the insurance company
    association(source = invoice, target = insuranceCompany) {
        source { multiplicity(spec = "1"); role = "submittedTo" }
        target { multiplicity(spec = "0..*"); role = "receives" }
    }
}

