}
class StorageLocation {
  +identifier: string
}
class Shipment {
  +trackingNumber: string
  +status: string "accepted, in warehouse, in transit, delivered"
}
class Package {
  +packageId: string
}
class Route {
  +routeId: string
}
class Segment {
  +segmentId: string
}
class Tour {
  +tourId: string
}
class TrackingContract {
  +contractId: string
}

Truck <|-- Vehicle
Van <|-- Vehicle

Warehouse "1" *-- "0..*" StorageLocation : contains
Shipment "1" *-- "1..*" Package : contains
Package "0..*" -- "0..1" StorageLocation : assigned to
Route "1" *-- "1..*" Segment : consists of

Segment "1" -- "1" Warehouse : source
Segment "1" -- "1" Warehouse : destination

Tour "1" -- "1" Vehicle : uses
Tour "1" -- "1" Driver : assigned to
Tour "1" -- "1" Route : follows
Tour "1" -- "0..*" Shipment : delivers

Shipment "1" -- "1" TrackingContract : uses
@enduml

classDiagram(name = "UniversityModel") {
    // Define all classes first
    val person = classOf(name = "Person") {
        isAbstract = true
        attribute(name = "name", type = "String")
        attribute(name = "dateOfBirth", type = "Date")
        attribute(name = "address", type = "String")
    }
    val student = classOf(name = "Student") {
        extends(general = person)
    }
    val professor = classOf(name = "Professor") {
        extends(general = person)
    }
    val university = classOf(name = "University") {
        attribute(name = "name", type = "String")
    }
    val faculty = classOf(name = "Faculty") {
        attribute(name = "name", type = "String")
    }
    val degreeProgram = classOf(name = "DegreeProgram") {
        attribute(name = "name", type = "String")
    }
    val module = classOf(name = "Module") {
        attribute(name = "name", type = "String")
        attribute(name = "code", type = "String")
    }
    val course = classOf(name = "Course") {
        attribute(name = "semester", type = "String")
    }
    val enrollment = classOf(name = "Enrollment") {
        attribute(name = "enrollmentDate", type = "Date")
    }
    val exam = classOf(name = "Exam") {
        attribute(name = "examDate", type = "Date")
    }
    val examinationPerformance = classOf(name = "ExaminationPerformance") {
        attribute(name = "grade", type = "String")
    }

    // Associations
    association(source = university, target = faculty) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "faculties" }
    }
    association(source = faculty, target = degreeProgram) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "programs" }
    }
    association(source = faculty, target = professor) {
        aggregation = AggregationKind.SHARED
        source { multiplicity(spec = "1"); role = "employs" }
        target { multiplicity(spec = "1..*"); role = "professors" }
    }
    association(source = degreeProgram, target = module) {
        aggregation = AggregationKind.SHARED
        source { multiplicity(spec = "1..*"); role = "bundles" }
        target { multiplicity(spec = "1..*"); role = "modules" }
    }
    association(source = module, target = course) {
        source { multiplicity(spec = "1..*"); role = "courses" }
        target { multiplicity(spec = "1"); role = "module" }
    }
    association(source = professor, target = course) {
        source { multiplicity(spec = "1"); role = "teaches" }
        target { multiplicity(spec = "1..*"); role = "taughtCourses" }
    }

    // Student enrollment in DegreeProgram via Enrollment
    association(source = student, target = enrollment) {
        source { multiplicity(spec = "1"); role = "student" }
        target { multiplicity(spec = "0..*"); role = "enrollments" }
    }
    association(source = degreeProgram, target = enrollment) {
        source { multiplicity(spec = "1"); role = "program" }
        target { multiplicity(spec = "0..*"); role = "enrollments" }
    }

    // Student completes ExaminationPerformance
    association(source = student, target = examinationPerformance) {
        source { multiplicity(spec = "1"); role = "student" }
        target { multiplicity(spec = "0..*"); role = "performances" }
    }
    // ExaminationPerformance belongs to Exam
    association(source = examinationPerformance, target = exam) {
        source { multiplicity(spec = "1..*"); role = "performances" }
        target { multiplicity(spec = "1"); role = "exam" }
    }
    // Exam assigned to Module
    association(source = exam, target = module) {
        source { multiplicity(spec = "1..*"); role = "exams" }
        target { multiplicity(spec = "1"); role = "module" }
    }
}

c4Model(name = "Blog Platform") {
    val author = person(name = "Author") { description = "Writes and publishes articles" }
    val reader = person(name = "Reader") { description = "Consumes published posts" }

    val blogPlatform = softwareSystem(name = "Blog Platform") {
        container(name = "Web Application") {
            technology = "React SPA & Spring Boot"
            description = "Serves articles to readers and provides editorial interface for authors"
        }
        container(name = "Content API") {
            technology = "Kotlin/Ktor"
            description = "Handles business logic for articles, publication, and notifications"
        }
        container(name = "Article Database") {
            technology = "PostgreSQL"
            description = "Stores all article content, metadata, and user information"
        }
    }

    val emailDeliveryService = softwareSystem(name = "Email Delivery Service") {
        external = true
        description = "Sends email notifications to subscribers"
    }

    relationship(source = author, target = blogPlatform) {
        technology = "HTTPS"
        description = "Writes and publishes articles via the Web Application"
    }
    relationship(source = reader, target = blogPlatform) {
        technology = "HTTPS"
        description = "Consumes published posts via the Web Application"
    }
    relationship(source = blogPlatform, target = emailDeliveryService) {
        technology = "API/SMTP"
        description = "Notifies subscribers on publication via the Content API"
    }

    containerDiagram(name = "Blog Platform - Container View") {
        system = blogPlatform
        showExternalSystems = true
    }
}

