c4Model(name = "Autonomous Driving Test Platform Model") {
    val testEngineer = person(name = "Test Engineer") { description = "Defines test campaigns." }
    val fleetManager = person(name = "Fleet Manager") { description = "Monitors vehicle status." }
    val dataAnalyst = person(name = "Data Analyst") { description = "Analyzes test run data and KPIs." }

    val testFleet = softwareSystem(name = "Test Fleet") { external = true; description = "Collection of real test vehicles." }
    val simulationEnv = softwareSystem(name = "Simulation Environment") { external = true; description = "Executes virtual simulations of autonomous driving functions." }
    val hdMapService = softwareSystem(name = "HD Map Service") { external = true; description = "Provides high-resolution map data." }
    val reqTicketing = softwareSystem(name = "Requirements & Ticketing System") { external = true; description = "Manages requirements and tracks issues." }

    val testPlatform = softwareSystem(name = "Autonomous Driving Test Platform") {
        // Containers are declared as val properties within the software system for external referencing
        val webInterface = container(name = "Web Interface") { technology = "React / Node.js"; description = "Allows engineers and managers to define test campaigns and monitor status." }
        val testOrchestrator = container(name = "Test Orchestrator") { technology = "Java/Spring Boot"; description = "Schedules and manages the execution of test runs." }
        val scenarioCatalog = container(name = "Scenario Catalog") { technology = "PostgreSQL / REST API"; description = "Stores and provides test scenarios and cases." }
        val ingestService = container(name = "Ingest Service") { technology = "Python/Flask"; description = "Receives measurement and sensor data from test vehicles." }
        val dataLake = container(name = "Data Lake") { technology = "Cloud Object Storage"; description = "Stores raw and processed measurement and sensor data." }
        val simulationManager = container(name = "Simulation Manager") { technology = "Java/Spring Boot"; description = "Dispatches scenarios and collects results from the simulation environment." }
        val evaluationService = container(name = "Evaluation Service") { technology = "Python/Spark"; description = "Analyzes test run results and checks them against expected values." }
        val analysisWorkbench = container(name = "Analysis Workbench") { technology = "Jupyter / Python"; description = "Provides data analysis and KPI computation capabilities via a notebook interface." }
    }

    // Relationships now correctly reference containers via the 'testPlatform' object and their declared val names
    relationship(source = testEngineer, target = testPlatform.webInterface) { technology = "HTTPS"; description = "Defines test campaigns using" }
    relationship(source = fleetManager, target = testPlatform.webInterface) { technology = "HTTPS"; description = "Monitors vehicle status using" }
    relationship(source = dataAnalyst, target = testPlatform.analysisWorkbench) { technology = "HTTPS"; description = "Examines collected runs using" }

    relationship(source = testFleet, target = testPlatform.ingestService) { technology = "MQTT/HTTPS"; description = "Uploads measurement & sensor data to" }
    relationship(source = testPlatform.ingestService, target = testPlatform.dataLake) { technology = "Cloud Storage API"; description = "Stores collected data in" }

    relationship(source = testPlatform.webInterface, target = testPlatform.testOrchestrator) { technology = "REST"; description = "Initiates test runs via" }
    relationship(source = testPlatform.webInterface, target = testPlatform.scenarioCatalog) { technology = "REST"; description = "Manages test scenarios in" }

    relationship(source = testPlatform.testOrchestrator, target = testPlatform.scenarioCatalog) { technology = "REST"; description = "Retrieves scenarios from" }
    relationship(source = testPlatform.testOrchestrator, target = testPlatform.simulationManager) { technology = "REST/gRPC"; description = "Dispatches simulation scenarios to" }
    relationship(source = testPlatform.testOrchestrator, target = testPlatform.evaluationService) { technology = "Message Queue"; description = "Triggers test result evaluation by" }
    relationship(source = testPlatform.testOrchestrator, target = testPlatform.dataLake) { technology = "Cloud Storage API"; description = "Stores test run metadata in" }

    relationship(source = testPlatform.simulationManager, target = simulationEnv) { technology = "REST/gRPC"; description = "Dispatches scenarios to" }
    relationship(source = simulationEnv, target = hdMapService) { technology = "REST/gRPC"; description = "Retrieves HD map data from" }
    relationship(source = simulationEnv, target = testPlatform.simulationManager) { technology = "REST/gRPC"; description = "Reports simulation results to" }
    relationship(source = testPlatform.simulationManager, target = testPlatform.dataLake) { technology = "Cloud Storage API"; description = "Stores simulation results in" }

    relationship(source = testPlatform.evaluationService, target = testPlatform.dataLake) { technology = "Cloud Storage API"; description = "Reads test data and results from" }
    relationship(source = testPlatform.evaluationService, target = reqTicketing) { technology = "REST"; description = "Reports detected deviations to" }

    relationship(source = testPlatform.analysisWorkbench, target = testPlatform.dataLake) { technology = "Cloud Storage API"; description = "Accesses collected runs directly in" }
    relationship(source = testPlatform.analysisWorkbench, target = reqTicketing) { technology = "REST"; description = "Reports detected deviations to" }

    containerDiagram(name = "Autonomous Driving Test Platform - Container View") { system = testPlatform; showExternalSystems = true }
}

c4Model(name = "Online Shop") {
    val customer = person(name = "Customer") { description = "Browses products, manages shopping cart, and places orders." }
    val shopManager = person(name = "Shop Manager") { description = "Manages the product assortment and prices." }

    val paymentGateway = softwareSystem(name = "Payment Gateway") {
        description = "An external service for processing credit card and other payments."
        external = true
    }
    val shippingService = softwareSystem(name = "Shipping Service Provider") {
        description = "An external service for commissioning and tracking package shipments."
        external = true
    }
    val emailMarketing = softwareSystem(name = "Email Marketing System") {
        description = "An external system used to send order confirmations and marketing communications."
        external = true
    }

    // Declare the main software system. Containers will be explicitly assigned to this parent.
    val onlineShop = softwareSystem(name = "Online Shop") {
        description = "An online shop built as a microservice landscape to sell products to customers."
    }

    // Declare containers as top-level vals so they can be referenced in relationships.
    // Use the 'parent' argument to associate them with the 'onlineShop' software system for correct hierarchy.
    val storefront = container(parent = onlineShop, name = "Storefront") {
        technology = "Web Application"
        description = "The customer-facing web application allowing product browsing, cart management, and order placement."
    }
    val adminApplication = container(parent = onlineShop, name = "Admin Application") {
        technology = "Web Application"
        description = "A web application for shop managers to manage products, prices, and orders."
    }
    val apiGateway = container(parent = onlineShop, name = "API Gateway") {
        technology = "API Gateway"
        description = "Routes and secures API requests from client applications to the backend microservices."
    }
    val productCatalogService = container(parent = onlineShop, name = "Product Catalog Service") {
        technology = "Microservice"
        description = "Manages product information, inventory, and catalog data."
    }
    val shoppingCartService = container(parent = onlineShop, name = "Shopping Cart Service") {
        technology = "Microservice"
        description = "Manages the state of customer shopping carts."
    }
    val orderProcessingService = container(parent = onlineShop, name = "Order Processing Service") {
        technology = "Microservice"
        description = "Coordinates the order lifecycle, from creation to payment and fulfillment."
    }
    val productDatabase = container(parent = onlineShop, name = "Product Database") {
        technology = "Relational Database"
        description = "Stores all product-related data, including descriptions, prices, and stock levels."
    }
    val shoppingCartDatabase = container(parent = onlineShop, name = "Shopping Cart Database") {
        technology = "NoSQL Database"
        description = "Stores customer shopping cart contents."
    }
    val orderDatabase = container(parent = onlineShop, name = "Order Database") {
        technology = "Relational Database"
        description = "Stores all order-related data, including customer details, items, and status."
    }
    val eventBus = container(parent = onlineShop, name = "Event Bus") {
        technology = "Message Broker (e.g., Kafka)"
        description = "A central asynchronous communication channel for microservices to exchange events."
    }

    // Relationships now directly reference the declared val names for all entities
    relationship(source = customer, target = storefront) {
        technology = "HTTPS"
        description = "Browses products and places orders using"
    }
    relationship(source = shopManager, target = adminApplication) {
        technology = "HTTPS"
        description = "Manages product data and prices using"
    }

    relationship(source = storefront, target = apiGateway) {
        technology = "HTTPS/REST"
        description = "Makes API requests to"
    }
    relationship(source = adminApplication, target = apiGateway) {
        technology = "HTTPS/REST"
        description = "Makes API requests to"
    }

    relationship(source = apiGateway, target = productCatalogService) {
        technology = "Internal API"
        description = "Routes requests for product data to"
    }
    relationship(source = apiGateway, target = shoppingCartService) {
        technology = "Internal API"
        description = "Routes requests for cart management to"
    }
    relationship(source = apiGateway, target = orderProcessingService) {
        technology = "Internal API"
        description = "Routes requests for order placement to"
    }

    relationship(source = productCatalogService, target = productDatabase) {
        technology = "SQL"
        description = "Reads and writes product data from/to"
    }
    relationship(source = shoppingCartService, target = shoppingCartDatabase) {
        technology = "NoSQL"
        description = "Reads and writes shopping cart data from/to"
    }
    relationship(source = orderProcessingService, target = orderDatabase) {
        technology = "SQL"
        description = "Reads and writes order data from/to"
    }

    relationship(source = productCatalogService, target = eventBus) {
        technology = "AMQP/Kafka"
        description = "Publishes product update events to"
    }
    relationship(source = shoppingCartService, target = eventBus) {
        technology = "AMQP/Kafka"
        description = "Publishes cart events and subscribes to product events via"
    }
    relationship(source = orderProcessingService, target = eventBus) {
        technology = "AMQP/Kafka"
        description = "Publishes order events and subscribes to cart/product events via"
    }

    relationship(source = orderProcessingService, target = paymentGateway) {
        technology = "REST API"
        description = "Processes payments via"
    }
    relationship(source = orderProcessingService, target = shippingService) {
        technology = "REST API"
        description = "Commissions shipping via"
    }
    relationship(source = orderProcessingService, target = emailMarketing) {
        technology = "API"
        description = "Sends order confirmations via"
    }

    containerDiagram(name = "Online Shop - Container View") { system = onlineShop; showExternalSystems = true }
}
